                                // append forced column to sort list 
                                if (config.sortAppend != null) {
                                    var a = config.sortAppend;
                                    for (var j = 0; j < a.length; j++) {
                                        if (a[j][0] != i) {
                                            config.sortList.push(a[j]);
                                        }
                                    }
                                } 

